-- The simplest possible SELECT: two columns from one table
SELECT meter_id, daily_kw
FROM   silver.meter_readings;

-- Find the distinct regions in HydroAlpes' meter readings
SELECT DISTINCT region
FROM   silver.meter_readings;

-- COUNT(*) counts every row, regardless of NULL values
SELECT COUNT(*) AS total_meters
FROM   silver.meters;

-- Add a new column for tariff code (regulatory requirement)
ALTER TABLE silver.meter_readings
  ADD COLUMN tariff_code VARCHAR(10);

-- Add a column with a default value
ALTER TABLE silver.meter_readings
  ADD COLUMN is_validated BOOLEAN DEFAULT FALSE;

-- Create an index on the date column for faster date-based filters
CREATE INDEX idx_meter_readings_date
  ON silver.meter_readings (date);

-- Create an index on region for faster region-based filters
CREATE INDEX idx_meter_readings_region
  ON silver.meter_readings (region);

